@pytest.mark.parametrize("expected", ACTION_EXPECTATIONS, ids=[item["name"] for item in ACTION_EXPECTATIONS])
def test_each_action_contract_fact_is_executable(expected):
    registry = ActionRegistry.default()

    action = registry.action(expected["action"])

    assert action.action_id == expected["action"]
    assert action.contract_statements[expected["kind"]].statement == expected["statement"]
    if expected["kind"] == "shared":
        assert action.shared_contract is True
    elif expected["kind"] == "mcp":
        assert action.mcp_tool_name == expected["value"]
    elif expected["kind"] == "cli_only":
        assert action.mcp_tool_name is None
        assert action.cli_only is True
    elif expected["kind"] == "mutation":
        assert action.mutation_mode.value == expected["value"]
    elif expected["kind"] == "required_input":
        assert expected["value"] in action.required_inputs
    elif expected["kind"] == "optional_input":
        assert expected["value"] in action.optional_inputs
    elif expected["kind"] == "no_required_inputs":
        assert action.required_inputs == []
    elif expected["kind"] == "no_optional_inputs":
        assert action.optional_inputs == []
    else:
        raise AssertionError(f"Unhandled action contract fact: {expected['kind']}")

