@pytest.mark.parametrize("expected", ACTIONS, ids=[item["action"] for item in ACTIONS])
def test_shared_action_contract_declares_interfaces_mutation_and_inputs(expected):
    registry = ActionRegistry.default()

    action = registry.action(expected["action"])

    assert action.action_id == expected["action"]
    assert action.shared_contract is expected["shared"]
    assert action.mutation_mode.value == expected["mutation"]
    assert action.required_inputs == expected["required"]
    assert action.optional_inputs == expected["optional"]
    if expected["mcp"] is None:
        assert action.mcp_tool_name is None
    else:
        assert action.mcp_tool_name == expected["mcp"]
    assert action.cli_command is not None


@pytest.mark.parametrize("expected", ACTION_CONTROLS, ids=[item["name"] for item in ACTION_CONTROLS])
def test_action_control_is_enforced(expected):
    registry = ActionRegistry.default()

    control = registry.control(expected["name"])

    assert control.statement == expected["statement"]
    assert control.target == expected["target"]
    assert control.enforced is True
    assert control.mutation_mode is MUTATION_VALUES[expected["mutation"]]
    assert control.blocks_invalid_invocation is expected["blocking"]


def test_json_patch_accepts_only_add_replace_and_remove_with_required_members():
    validator = JsonPatchValidator(existing_document={"title": "Old", "tags": ["api"]})

    valid = validator.validate([
        {"op": "replace", "path": "/title", "value": "New"},
        {"op": "add", "path": "/tags/1", "value": "docs"},
        {"op": "remove", "path": "/tags/0"},
    ])
    invalid = validator.validate([
        {"op": "copy", "from": "/title", "path": "/summary"},
        {"op": "replace", "path": "/missing"},
    ])

    assert valid.allowed is True
    assert invalid.allowed is False
    assert [diagnostic.code for diagnostic in invalid.diagnostics] == [
        "json_patch_operation_not_allowed",
        "json_patch_value_required",
    ]


def test_human_gated_action_generates_prompt_id_from_canonical_prompt_when_absent():
    kernel = SpecGuardKernel.in_memory(project_id="project-alpha")

    result = kernel.actions.invoke(
        "work.approve",
        {
            "work_id": "WP-2",
            "selected_number": 1,
            "raw_response": "1",
            "decision_prompt": "Approve packet WP-2?",
            "human_confirmed": True,
            "review_snapshot_hash": "sha256:abc",
            "review_snapshot_revision": "work:WP-2@4",
            "source_artifact_refs": [{"artifact_type": "work_packet", "id": "WP-2", "revision": 4}],
        },
    )

    assert result.data.human_decision.prompt_id.startswith("prompt:work.approve:")
    assert result.data.human_decision.review_snapshot_hash == "sha256:abc"
